using ModelContextProtocol.Server;
using System.Text.Json;

namespace McpHttpServer;

public class ConfigurationResourceProvider
{
    [McpServerResource(
        Name = "app-config",
        Uri = "config://app/settings",
        Description = "Returns current application configuration data.")]
    public static string GetAppConfiguration()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            Features = new { EnableCaching = true, MaxConnections = 100 }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

